def handle_command(command_data, client_socket):
    try:
        cmd = json.loads(command_data)
    except (ValueError, TypeError):
        error_response = json.dumps({
            "type": "error",
            "message": "Invalid JSON format"
        })
        client_socket.send(encode_websocket_frame(error_response))
        return

    action = cmd.get("action", "")
    target = cmd.get("target", "led")
    value = cmd.get("value", None)
    response = {"type": "response", "action": action, "success": True}

    print("Command received:", action, "target:", target, "value:", value)

    if action == "turn_on":
        if target == "led":
            led.value(1)
            device_state["led"] = True
            response["message"] = "LED turned ON"
        elif target == "relay":
            relay.value(1)
            device_state["relay"] = True
            response["message"] = "Relay turned ON"
        else:
            response["success"] = False
            response["message"] = "Unknown target: {}".format(target)

    elif action == "turn_off":
        if target == "led":
            led.value(0)
            device_state["led"] = False
            response["message"] = "LED turned OFF"
        elif target == "relay":
            relay.value(0)
            device_state["relay"] = False
            response["message"] = "Relay turned OFF"
        else:
            response["success"] = False
            response["message"] = "Unknown target: {}".format(target)

    elif action == "toggle":
        if target == "led":
            new_val = not device_state["led"]
            led.value(1 if new_val else 0)
            device_state["led"] = new_val
            response["message"] = "LED toggled to {}".format("ON" if new_val else "OFF")
        elif target == "relay":
            new_val = not device_state["relay"]
            relay.value(1 if new_val else 0)
            device_state["relay"] = new_val
            response["message"] = "Relay toggled to {}".format("ON" if new_val else "OFF")
        else:
            response["success"] = False
            response["message"] = "Unknown target: {}".format(target)

    elif action == "set_brightness":
        if value is not None:
            brightness = max(0, min(100, int(value)))
            device_state["brightness"] = brightness
            # If using PWM for LED brightness
            try:
                pwm = machine.PWM(led, freq=1000)
                pwm.duty(int(brightness * 10.23))  # 0-1023 range
            except Exception:
                pass
            response["message"] = "Brightness set to {}".format(brightness)
        else:
            response["success"] = False
            response["message"] = "Missing 'value' for brightness"

    elif action == "get_state":
        state_msg = get_state_json()
        client_socket.send(encode_websocket_frame(state_msg))
        return

    elif action == "ping":
        response["message"] = "pong"
        response["timestamp"] = time.ticks_ms()

    elif action == "restart":
        response["message"] = "Device restarting..."
        client_socket.send(encode_websocket_frame(json.dumps(response)))
        time.sleep(1)
        machine.reset()
        return

    elif action == "info":
        response["device"] = {
            "platform": os.uname().machine,
            "version": os.uname().version,
            "free_mem": gc_free_mem(),
            "uptime": device_state["uptime"]
        }
        response["message"] = "Device info"

    else:
        response["success"] = False
        response["message"] = "Unknown action: {}".format(action)

    response_json = json.dumps(response)
    client_socket.send(encode_websocket_frame(response_json))

    # Broadcast state update to all clients
    if response.get("success", False):
        broadcast_message(get_state_json(), exclude=None)


def gc_free_mem():
    try:
        import gc
        gc.collect()
        return gc.mem_free()
    except Exception:
        return 0


def read_sensor_data():
    """Read sensor data - customize for your sensors"""
    # Example: reading internal temperature (ESP32)
    try:
        import esp32
        tf = esp32.raw_temperature()
        device_state["temperature"] = round((tf - 32) / 1.8, 1)
    except Exception:
        device_state["temperature"] = 0.0


