def serve_http_page(client_socket):
    response = (
        "HTTP/1.1 200 OK\r\n"
        "Content-Type: text/html\r\n"
        "Connection: close\r\n"
        "Content-Length: {}\r\n"
        "\r\n"
    ).format(len(HTML_PAGE))
    client_socket.send(response.encode("utf-8"))
    # Send in chunks to avoid memory issues
    chunk_size = 1024
    for i in range(0, len(HTML_PAGE), chunk_size):
        client_socket.send(HTML_PAGE[i:i + chunk_size].encode("utf-8"))


def handle_websocket_client(client_socket, client_addr):
    print("WebSocket client connected:", client_addr)

    clients_lock.acquire()
    clients.append(client_socket)
    clients_lock.release()

    # Send initial state
    try:
        state_msg = get_state_json()
        client_socket.send(encode_websocket_frame(state_msg))
    except Exception:
        pass

    buffer = b""

    while True:
        try:
            data = client_socket.recv(1024)
            if not data:
                break

            buffer += data

            while len(buffer) >= 2:
                opcode, payload = decode_websocket_frame(buffer)

                if opcode is None:
                    break

                # Calculate frame size to remove from buffer
                frame_len = 2
                pl = buffer[1] & 0x7F
                masked = (buffer[1] & 0x80) != 0
                if pl == 126:
                    frame_len = 4
                    actual_pl = struct.unpack(">H", buffer[2:4])[0]
                elif pl == 127:
                    frame_len = 10
                    actual_pl = struct.unpack(">Q", buffer[2:10])[0]
                else:
                    actual_pl = pl
                if masked:
                    frame_len += 4
                frame_len += actual_pl
                buffer = buffer[frame_len:]

                if opcode == 0x01:  # Text frame
                    try:
                        message = payload.decode("utf-8")
                        print("Received:", message)
                        handle_command(message, client_socket)
                    except Exception as e:
                        print("Error handling command:", e)
                        error_resp = json.dumps({
                            "type": "error",
                            "message": str(e)
                        })
                        try:
                            client_socket.send(encode_websocket_frame(error_resp))
                        except Exception:
                            pass

                elif opcode == 0x08:  # Close frame
                    send_close_frame(client_socket)
                    break

                elif opcode == 0x09:  # Ping
                    send_pong(client_socket, payload)

                elif opcode == 0x0A:  # Pong
                    pass

            if opcode == 0x08:
                break

        except OSError as e:
            print("Socket error:", e)
            break
        except Exception as e:
            print("Error:", e)
            break

    # Clean up
    clients_lock.acquire()
    if client_socket in clients:
        clients.remove(client_socket)
    clients_lock.release()

    try:
        client_socket.close()
    except Exception:
        pass

    print("WebSocket client disconnected:", client_addr)


def handle_client_connection(client_socket, client_addr):
    try:
        client_socket.settimeout(10)
        data = client_socket.recv(2048)
        if not data:
            client_socket.close()
            return

        request_line, headers = parse_http_request(data)

        # Check if this is a WebSocket upgrade request
        upgrade = headers.get("upgrade", "").lower()
        if upgrade == "websocket":
            if websocket_handshake(client_socket, headers):
                client_socket.settimeout(None)
                handle_websocket_client(client_socket, client_addr)
            else:
                client_socket.close()
        else:
            # Serve the HTML control page
            serve_http_page(client_socket)
            client_socket.close()

    except Exception as e:
        print("Client handler error:", e)
        try:
            client_socket.close()
        except Exception:
            pass


def http_server_thread(ip_addr):
    """HTTP server for serving the control page"""
    http_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    http_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    http_socket.bind(("0.0.0.0", 80))
    http_socket.listen(5)
    print("HTTP server listening on http://{}:80".format(ip_addr))

    while True:
        try:
            client, addr = http_socket.accept()
            try:
                client.settimeout(10)
                data = client.recv(2048)
                if data:
                    serve_http_page(client)
            except Exception as e:
                print("HTTP error:", e)
            finally:
                try:
                    client.close()
                except Exception:
                    pass
        except Exception as e:
            print("HTTP accept error:", e)
            time.sleep(1)


def sensor_update_thread():
    """Periodically read sensors and broadcast updates"""
    start_time = time.ticks_ms()
    while True:
        time.sleep(10)
        device_state["uptime"] = time.ticks_diff(time.ticks_ms(), start_time) // 1000
        read_sensor_data()
        if clients:
            broadcast_message(get_state_json())


def start_server():
    import gc
    gc.collect()

    ip_addr = connect_wifi()
    if not ip_addr:
        print("Cannot start server without WiFi")
        return

    # Initialize device state from hardware
    device_state["led"] = bool(led.value())
    device_state["relay"] = bool(relay.value())

    # Start HTTP server in a thread
    _thread.start_new_thread(http_server_thread, (ip_addr,))

    # Start sensor update thread
    _thread.start_new_thread(sensor_update_thread, ())

    # WebSocket server on main thread
    ws_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    ws_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    ws_socket.bind(("0.0.0.0", WS_PORT))
    ws_socket.listen(5)

    print("WebSocket server listening on ws://{}:{}".format(ip_addr, WS_PORT))
    print("Open http://{}/ in your browser for the control panel".format(ip_addr))

    while True:
        try:
            client, addr = ws_socket.accept()
            print("New connection from:", addr)
            _thread.start_new_thread(handle_client_connection, (client, addr))
        except Exception as e:
            print("Accept error:", e)
            time.sleep(1)


# Entry point
if __name__ == "__main__":
    start_server()